import type { NeemRuntimeWorkerContext } from '@nmtjs/neem'
import { defineRuntimeWorker } from '@nmtjs/neem'

import { record } from '../../../../../shared/support/_events.ts'

type BarePackageWorkerOptions = { label: string }
type BarePackageWorkerDefinition = { fixture: 'bare-package-entry' }

export default defineRuntimeWorker<
  BarePackageWorkerOptions,
  BarePackageWorkerDefinition
>({
  definition: { fixture: 'bare-package-entry' },
  createRuntime(
    ctx: NeemRuntimeWorkerContext<
      BarePackageWorkerOptions,
      BarePackageWorkerDefinition
    >,
  ) {
    record({
      event: 'bare-package-worker-create',
      name: ctx.name,
      data: ctx.data,
      definition: ctx.definition,
    })

    return {
      start() {
        record({ event: 'bare-package-worker-start', name: ctx.name })
      },
      stop() {
        record({ event: 'bare-package-worker-stop', name: ctx.name })
      },
    }
  },
})
